import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';
import RentalCard from '../components/RentalCard'; // Importing the updated card below

const SORT_COLUMNS = [
  { value: 'price', label: 'Price' },
  { value: 'bedrooms', label: 'Bedrooms' },
  { value: 'bathrooms', label: 'Bathrooms' },
  { value: 'parking_spaces', label: 'Parking' },
  { value: 'suburb', label: 'Suburb' },
];

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  // Form state from main code
  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    property_type: searchParams.get('property_type') || '',
    min_price: searchParams.get('min_price') || '',
    max_price: searchParams.get('max_price') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parking_spaces: searchParams.get('parking_spaces') || '',
    sort_col: searchParams.get('sort_col') || '',
    sort_order: searchParams.get('sort_order') || 'asc',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);
  const [showAdvanced, setShowAdvanced] = useState(false);

  const debounceRef = useRef(null);

  // Load filter options
  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);
    try {
      const params = { ...currentFilters, page: currentPage };
      Object.keys(params).forEach((k) => {
        if (params[k] === '' || params[k] == null) delete params[k];
      });
      const data = await searchRentals(params);
      setResults(data);
    } catch (err) {
      setError(err.message || 'Search failed. Please try again.');
    } finally {
      setLoading(false);
    }
  }, []);

  // Sync URL and Debounce
  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);
      const params = {};
      Object.entries(filters).forEach(([k, v]) => { if (v) params[k] = v; });
      if (page > 1) params.page = page;
      setSearchParams(params, { replace: true });
    }, 400);
    return () => clearTimeout(debounceRef.current);
  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
    setPage(1);
  };

  const handleSortCol = (col) => {
    setFilters((prev) => ({
      ...prev,
      sort_col: col,
      sort_order: prev.sort_col === col && prev.sort_order === 'asc' ? 'desc' : 'asc',
    }));
    setPage(1);
  };

  const resetFilters = () => {
    setFilters({
      state: '', suburb: '', postcode: '', property_type: '',
      min_price: '', max_price: '', bedrooms: '', bathrooms: '',
      parking_spaces: '', sort_col: '', sort_order: 'asc',
    });
    setPage(1);
  };

  const rentals = results?.rentals || results?.data || results || [];
  const totalPages = results?.pagination?.lastPage || results?.lastPage || 1;

  return (
    <div className="search-page">
      <aside className="search-sidebar">
        <div className="filter-panel">
          <div className="filter-panel__header">
            <h2>Filters</h2>
            <button className="btn-reset" onClick={resetFilters}>Reset</button>
          </div>

          <div className="filter-group">
            <label>State</label>
            <select value={filters.state} onChange={(e) => handleFilterChange('state', e.target.value)}>
              <option value="">All States</option>
              {states.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label>Suburb</label>
            <input
              type="text"
              placeholder="e.g. Surry Hills"
              value={filters.suburb}
              onChange={(e) => handleFilterChange('suburb', e.target.value)}
            />
          </div>

          <button className="advanced-toggle" onClick={() => setShowAdvanced(!showAdvanced)}>
            {showAdvanced ? '− Hide Advanced' : '+ Show Advanced'}
          </button>

          {showAdvanced && (
            <div className="advanced-content">
              <div className="filter-row">
                <div className="filter-group">
                  <label>Min Price</label>
                  <input type="number" placeholder="0" value={filters.min_price} onChange={(e) => handleFilterChange('min_price', e.target.value)} />
                </div>
                <div className="filter-group">
                  <label>Max Price</label>
                  <input type="number" placeholder="Any" value={filters.max_price} onChange={(e) => handleFilterChange('max_price', e.target.value)} />
                </div>
              </div>
              <div className="filter-group">
                <label>Property Type</label>
                <select value={filters.property_type} onChange={(e) => handleFilterChange('property_type', e.target.value)}>
                  <option value="">All Types</option>
                  {propertyTypes.map((t) => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
            </div>
          )}
        </div>
      </aside>

      <main className="search-results-container">
        <div className="results-toolbar">
          <div className="results-count">
             <h1>{loading ? 'Searching...' : `${rentals.length} Properties`}</h1>
          </div>
          <div className="sort-options">
            {SORT_COLUMNS.map((c) => (
              <button
                key={c.value}
                className={`sort-chip ${filters.sort_col === c.value ? 'active' : ''}`}
                onClick={() => handleSortCol(c.value)}
              >
                {c.label} {filters.sort_col === c.value && (filters.sort_order === 'asc' ? '↑' : '↓')}
              </button>
            ))}
          </div>
        </div>

        {loading && <LoadingState message="Fetching the best properties..." />}
        {!loading && error && <ErrorState message={error} onRetry={() => doSearch(filters, page)} />}
        
        {!loading && !error && rentals.length === 0 && (
          <EmptyState title="No properties found" subtitle="Try loosening your filters." />
        )}

        {!loading && !error && rentals.length > 0 && (
          <>
            <div className="results-grid">
              {rentals.map((r) => (
                <RentalCard key={r.id} rental={r} />
              ))}
            </div>
            <Pagination page={page} totalPages={totalPages} onPageChange={setPage} />
          </>
        )}
      </main>
    </div>
  );
};

export default SearchPage;
